1	export type Cell = [number, number];
2	
3	function isNeighbor(cell: Cell, other: Cell): boolean {
4	  const sameCell = other[0] === cell[0] && other[1] === cell[1];
5	  return (
6	    !sameCell &&
7	    Math.abs(other[0] - cell[0]) <= 1 &&
8	    Math.abs(other[1] - cell[1]) <= 1
9	  );
10	}
11	
12	function countNeighbors(cell: Cell, cells: Cell[]): number {
13	  return cells.filter((other) => isNeighbor(cell, other)).length;
14	}
15	
16	export function nextGeneration(cells: Cell[]): Cell[] {
17	  return cells.filter((cell) => {
18	    const neighborCount = countNeighbors(cell, cells);
19	    return neighborCount === 2 || neighborCount === 3;
20	  });
21	}
